#!/usr/bin/env node

const https = require('https');
const http = require('http');
const fs = require('fs');
const path = require('path');
const { URL } = require('url');

async function fetchDomain(domain, timeout = 10000) {
  return new Promise((resolve) => {
    const urlToFetch = `https://${domain}`;

    try {
      const parsedUrl = new URL(urlToFetch);
      const options = {
        hostname: parsedUrl.hostname,
        port: parsedUrl.port || 443,
        path: parsedUrl.pathname + parsedUrl.search,
        method: 'GET',
        timeout: timeout,
        headers: {
          'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36',
          'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
          'Accept-Language': 'en-US,en;q=0.9',
          'Connection': 'close'
        }
      };

      const protocol = parsedUrl.protocol === 'https:' ? https : http;

      const req = protocol.request(options, (res) => {
        let data = '';

        res.on('data', (chunk) => {
          data += chunk;
          // Limit data collection to first 100KB
          if (data.length > 100000) {
            req.destroy();
          }
        });

        res.on('end', () => {
          resolve({
            success: true,
            statusCode: res.statusCode,
            html: data,
            headers: res.headers
          });
        });
      });

      req.on('error', (error) => {
        resolve({
          success: false,
          error: error.message
        });
      });

      req.on('timeout', () => {
        req.destroy();
        resolve({
          success: false,
          error: 'Timeout'
        });
      });

      req.end();
    } catch (error) {
      resolve({
        success: false,
        error: error.message
      });
    }
  });
}

function extractTitle(html) {
  const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  if (titleMatch) {
    return titleMatch[1].trim()
      .replace(/\s*[\|\-–—]\s*(Home|Shop|Store|Official|Website).*$/i, '')
      .trim();
  }
  return '';
}

function extractMetaDescription(html) {
  const metaMatch = html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']/i);
  if (metaMatch) {
    return metaMatch[1].substring(0, 200);
  }
  return '';
}

function detectShopifyPlus(html, headers) {
  const indicators = [
    /shopify-plus/i,
    /x-shopify-stage/i,
    /cdn\.shopify\.com\/shopifycloud\/shopify_pay/i,
    /Shopify\.shop.*=.*"/i
  ];

  const htmlCheck = indicators.some(pattern => pattern.test(html));
  const headerCheck = headers['x-shopify-stage'] || headers['x-shopify-shop'];

  return htmlCheck || headerCheck;
}

function hasProducts(html) {
  const productIndicators = [
    /product[s]?\.json/i,
    /"product":/i,
    /productType/i,
    /add[\-\s]?to[\-\s]?cart/i,
    /shop[\s\-]?now/i,
    /buy[\s\-]?now/i,
    /<meta[^>]*property=["']og:type["'][^>]*content=["']product/i,
    /class=["'][^"']*product[^"']*["']/i
  ];

  return productIndicators.some(pattern => pattern.test(html));
}

function analyzeCategory(html, existingCategory) {
  const lowercaseHtml = html.toLowerCase();
  const metaContent = extractMetaDescription(html).toLowerCase();
  const title = extractTitle(html).toLowerCase();
  const combinedText = `${title} ${metaContent} ${lowercaseHtml.substring(0, 5000)}`;

  const categoryKeywords = {
    'Fashion': ['fashion', 'clothing', 'apparel', 'wear', 'style', 'boutique', 'dress', 'shirt', 'pants', 'jeans'],
    'Beauty': ['beauty', 'makeup', 'cosmetic', 'skincare', 'serum', 'moisturizer', 'lipstick', 'foundation'],
    'Fitness': ['fitness', 'workout', 'gym', 'athletic', 'activewear', 'sport', 'training', 'exercise'],
    'Food': ['food', 'snack', 'nutrition', 'supplement', 'vitamin', 'meal', 'recipe', 'organic', 'healthy eating'],
    'Home': ['home', 'furniture', 'decor', 'bedding', 'mattress', 'pillow', 'sheet', 'interior'],
    'Lifestyle': ['lifestyle', 'living', 'wellness', 'self-care', 'daily', 'routine'],
    'Jewelry': ['jewelry', 'jewellery', 'necklace', 'ring', 'bracelet', 'earring', 'gold', 'silver'],
    'Pet': ['pet', 'dog', 'cat', 'puppy', 'kitten', 'animal'],
    'Footwear': ['shoe', 'sneaker', 'boot', 'sandal', 'footwear', 'feet'],
    'Accessories': ['accessories', 'bag', 'wallet', 'watch', 'sunglasses', 'belt', 'hat']
  };

  const scores = {};
  for (const [category, keywords] of Object.entries(categoryKeywords)) {
    scores[category] = keywords.filter(kw => combinedText.includes(kw)).length;
  }

  const topCategory = Object.entries(scores)
    .filter(([_, score]) => score > 0)
    .sort((a, b) => b[1] - a[1])[0];

  if (topCategory && topCategory[1] > 1) {
    return topCategory[0];
  }

  return existingCategory || 'General';
}

async function enrichStore(store, index, total) {
  console.log(`[${index + 1}/${total}] Enriching: ${store.domain}`);

  const result = await fetchDomain(store.domain);

  if (!result.success) {
    console.log(`  ✗ Failed: ${result.error}`);
    return {
      ...store,
      active: 'unknown',
      verified: false,
      error: result.error
    };
  }

  const title = extractTitle(result.html);
  const description = extractMetaDescription(result.html);
  const hasShopify = detectShopifyPlus(result.html, result.headers);
  const hasProds = hasProducts(result.html);
  const category = analyzeCategory(result.html, store.category);

  console.log(`  ✓ Active: ${hasProds ? 'Yes' : 'No'} | Title: ${title.substring(0, 40)}...`);

  return {
    domain: store.domain,
    name: title || store.name,
    category: category,
    active: hasProds ? 'yes' : 'no',
    source: store.source,
    notes: store.notes || (hasShopify ? 'Confirmed Shopify Plus' : ''),
    verified: true,
    description: description
  };
}

async function main() {
  const rawDataPath = path.join('/job/data', 'shopify-leads-raw.json');

  if (!fs.existsSync(rawDataPath)) {
    console.error('Error: shopify-leads-raw.json not found. Run scraper first.');
    process.exit(1);
  }

  const stores = JSON.parse(fs.readFileSync(rawDataPath, 'utf8'));
  console.log(`Starting enrichment for ${stores.length} stores...\n`);

  const enrichedStores = [];
  const batchSize = 5;

  for (let i = 0; i < stores.length; i += batchSize) {
    const batch = stores.slice(i, Math.min(i + batchSize, stores.length));
    const enrichedBatch = await Promise.all(
      batch.map((store, idx) => enrichStore(store, i + idx, stores.length))
    );
    enrichedStores.push(...enrichedBatch);

    // Small delay between batches
    if (i + batchSize < stores.length) {
      await new Promise(resolve => setTimeout(resolve, 2000));
    }
  }

  // Save enriched data
  const enrichedPath = path.join('/job/data', 'shopify-leads-enriched.json');
  fs.writeFileSync(enrichedPath, JSON.stringify(enrichedStores, null, 2));

  console.log(`\n✓ Enrichment complete!`);
  console.log(`  Total stores: ${enrichedStores.length}`);
  console.log(`  Active stores: ${enrichedStores.filter(s => s.active === 'yes').length}`);
  console.log(`  Saved to: ${enrichedPath}`);
}

if (require.main === module) {
  main().catch(console.error);
}

module.exports = { enrichStore };

#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

function escapeCSV(value) {
  if (value === null || value === undefined) return '';
  const str = String(value);
  if (str.includes(',') || str.includes('"') || str.includes('\n')) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
}

function priorityScore(store) {
  let score = 0;

  // Active stores get priority
  if (store.active === 'yes') score += 100;

  // UGC-ready categories (visual products)
  const visualCategories = ['Fashion', 'Beauty', 'Fitness', 'Footwear', 'Jewelry', 'Accessories', 'Home'];
  if (visualCategories.some(cat => store.category && store.category.includes(cat))) {
    score += 50;
  }

  // Known UGC app users get bonus
  if (store.source && store.source.includes('App')) {
    score += 30;
  }

  // Stores with notes (especially UGC-related) get priority
  if (store.notes && (
    store.notes.includes('UGC') || 
    store.notes.includes('photo') || 
    store.notes.includes('review')
  )) {
    score += 20;
  }

  // Known brands (no error) get priority
  if (store.verified && !store.error) {
    score += 10;
  }

  return score;
}

function categorizeForUGC(category) {
  const ugcFriendlyCategories = [
    'Fashion',
    'Beauty',
    'Fitness',
    'Food',
    'Footwear',
    'Jewelry',
    'Accessories',
    'Home',
    'Lifestyle',
    'Pet'
  ];

  for (const ugcCat of ugcFriendlyCategories) {
    if (category && category.includes(ugcCat)) {
      return true;
    }
  }
  return false;
}

function main() {
  const enrichedPath = path.join('/job/data', 'shopify-leads-enriched.json');

  if (!fs.existsSync(enrichedPath)) {
    console.error('Error: shopify-leads-enriched.json not found. Run enrichment first.');
    process.exit(1);
  }

  let stores = JSON.parse(fs.readFileSync(enrichedPath, 'utf8'));

  console.log(`Generating CSV from ${stores.length} stores...\n`);

  // Filter for UGC-friendly categories and active stores
  const filteredStores = stores.filter(store => {
    const isActive = store.active === 'yes' || store.active === 'unknown';
    const isUGCFriendly = categorizeForUGC(store.category);
    return isActive && isUGCFriendly;
  });

  console.log(`After filtering:`);
  console.log(`  UGC-friendly & active: ${filteredStores.length}`);

  // Add priority scores and sort
  const scoredStores = filteredStores.map(store => ({
    ...store,
    priority: priorityScore(store)
  }));

  scoredStores.sort((a, b) => {
    // Sort by priority score (descending)
    if (b.priority !== a.priority) return b.priority - a.priority;
    // Then by category
    if (a.category !== b.category) return (a.category || '').localeCompare(b.category || '');
    // Then by name
    return (a.name || '').localeCompare(b.name || '');
  });

  // Generate CSV
  const headers = ['Domain', 'Brand Name', 'Category', 'Active', 'Source', 'Notes'];
  const csvLines = [headers.join(',')];

  for (const store of scoredStores) {
    const row = [
      escapeCSV(store.domain),
      escapeCSV(store.name),
      escapeCSV(store.category),
      escapeCSV(store.active),
      escapeCSV(store.source),
      escapeCSV(store.notes)
    ];
    csvLines.push(row.join(','));
  }

  const csvPath = path.join('/job/data', 'shopify-plus-leads.csv');
  fs.writeFileSync(csvPath, csvLines.join('\n'));

  console.log(`\n✓ CSV generated: ${csvPath}`);
  console.log(`  Total leads: ${scoredStores.length}`);

  // Show breakdown by category
  const categoryBreakdown = {};
  scoredStores.forEach(store => {
    const cat = store.category || 'Other';
    categoryBreakdown[cat] = (categoryBreakdown[cat] || 0) + 1;
  });

  console.log(`\nCategory breakdown:`);
  Object.entries(categoryBreakdown)
    .sort((a, b) => b[1] - a[1])
    .forEach(([cat, count]) => {
      console.log(`  ${cat}: ${count}`);
    });

  // Show top 10 leads
  console.log(`\nTop 10 priority leads:`);
  scoredStores.slice(0, 10).forEach((store, i) => {
    console.log(`  ${i + 1}. ${store.name} (${store.domain}) - ${store.category}`);
  });
}

if (require.main === module) {
  main();
}

module.exports = { priorityScore, categorizeForUGC };

