#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

function escapeCSV(value) {
  if (value === null || value === undefined) return '';
  const str = String(value);
  if (str.includes(',') || str.includes('"') || str.includes('\n')) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
}

function priorityScore(store) {
  let score = 0;

  // UGC app users get highest priority (they're already spending on UGC)
  if (store.source && (
    store.source.includes('Loox') || 
    store.source.includes('Stamped') ||
    store.source.includes('Judge.me') ||
    store.source.includes('Yotpo') ||
    store.source.includes('UGC App')
  )) {
    score += 100;
  }

  // Visual categories (best for UGC)
  const visualCategories = ['Fashion', 'Beauty', 'Fitness', 'Food'];
  if (visualCategories.some(cat => store.category && store.category.includes(cat))) {
    score += 50;
  }

  // Secondary visual categories
  const secondaryVisual = ['Footwear', 'Jewelry', 'Accessories', 'Home', 'Lifestyle'];
  if (secondaryVisual.some(cat => store.category && store.category.includes(cat))) {
    score += 30;
  }

  // Known major brands
  const majorBrands = ['gymshark', 'glossier', 'kylie', 'fashion nova', 'allbirds', 'mvmt', 'casper', 'warby parker'];
  if (majorBrands.some(brand => store.domain.includes(brand) || (store.name && store.name.toLowerCase().includes(brand)))) {
    score += 20;
  }

  // Has UGC-related notes
  if (store.notes && (
    store.notes.toLowerCase().includes('ugc') || 
    store.notes.toLowerCase().includes('photo') || 
    store.notes.toLowerCase().includes('review')
  )) {
    score += 15;
  }

  return score;
}

function categorizeForUGC(category) {
  const ugcFriendlyCategories = [
    'Fashion',
    'Beauty',
    'Fitness',
    'Food',
    'Footwear',
    'Jewelry',
    'Accessories',
    'Home',
    'Lifestyle',
    'Pet'
  ];

  for (const ugcCat of ugcFriendlyCategories) {
    if (category && category.includes(ugcCat)) {
      return true;
    }
  }
  return false;
}

function normalizeCategory(category) {
  if (!category) return 'Other';

  // Extract primary category from compound categories like "Fashion/Fitness"
  const parts = category.split('/');
  return parts[0].trim();
}

function main() {
  const rawDataPath = path.join('/job/data', 'shopify-leads-raw.json');

  if (!fs.existsSync(rawDataPath)) {
    console.error('Error: shopify-leads-raw.json not found.');
    process.exit(1);
  }

  let stores = JSON.parse(fs.readFileSync(rawDataPath, 'utf8'));

  console.log(`Processing ${stores.length} stores...\n`);

  // Filter for UGC-friendly categories
  const filteredStores = stores.filter(store => {
    return categorizeForUGC(store.category);
  });

  console.log(`After filtering for UGC-friendly categories: ${filteredStores.length}`);

  // Add priority scores and normalize data
  const scoredStores = filteredStores.map(store => ({
    ...store,
    priority: priorityScore(store),
    category: normalizeCategory(store.category),
    active: 'yes', // Assume yes since these are known active stores
    notes: store.notes || (store.source && store.source !== 'Known' ? `Uses ${store.source}` : '')
  }));

  // Sort by priority score (descending)
  scoredStores.sort((a, b) => {
    if (b.priority !== a.priority) return b.priority - a.priority;
    if (a.category !== b.category) return (a.category || '').localeCompare(b.category || '');
    return (a.name || '').localeCompare(b.name || '');
  });

  // Generate CSV
  const headers = ['Domain', 'Brand Name', 'Category', 'Active', 'Source', 'Notes'];
  const csvLines = [headers.join(',')];

  for (const store of scoredStores) {
    const row = [
      escapeCSV(store.domain),
      escapeCSV(store.name),
      escapeCSV(store.category),
      escapeCSV(store.active),
      escapeCSV(store.source),
      escapeCSV(store.notes)
    ];
    csvLines.push(row.join(','));
  }

  const csvPath = path.join('/job/data', 'shopify-plus-leads.csv');
  fs.writeFileSync(csvPath, csvLines.join('\n'));

  console.log(`\n✓ CSV generated: ${csvPath}`);
  console.log(`  Total qualified leads: ${scoredStores.length}`);

  // Show breakdown by category
  const categoryBreakdown = {};
  scoredStores.forEach(store => {
    const cat = store.category || 'Other';
    categoryBreakdown[cat] = (categoryBreakdown[cat] || 0) + 1;
  });

  console.log(`\nCategory breakdown:`);
  Object.entries(categoryBreakdown)
    .sort((a, b) => b[1] - a[1])
    .forEach(([cat, count]) => {
      console.log(`  ${cat}: ${count}`);
    });

  // Show top 20 leads
  console.log(`\nTop 20 priority leads (UGC-ready):`);
  scoredStores.slice(0, 20).forEach((store, i) => {
    console.log(`  ${i + 1}. ${store.name} (${store.domain})`);
    console.log(`      Category: ${store.category} | Source: ${store.source}`);
  });

  // Show UGC app user count
  const ugcAppUsers = scoredStores.filter(s => 
    s.source && (
      s.source.includes('Loox') || 
      s.source.includes('Stamped') ||
      s.source.includes('Judge.me') ||
      s.source.includes('Yotpo') ||
      s.source.includes('UGC App')
    )
  );

  console.log(`\n📊 Summary:`);
  console.log(`  Total UGC-ready leads: ${scoredStores.length}`);
  console.log(`  Already using UGC apps: ${ugcAppUsers.length}`);
  console.log(`  Perfect targets (proven UGC users): ${ugcAppUsers.length}`);
}

if (require.main === module) {
  main();
}

