#!/usr/bin/env node

const fs = require('fs');
const path = require('path');

function main() {
  const rawDataPath = path.join('/job/data', 'shopify-leads-raw.json');

  if (!fs.existsSync(rawDataPath)) {
    console.error('Error: shopify-leads-raw.json not found.');
    process.exit(1);
  }

  let stores = JSON.parse(fs.readFileSync(rawDataPath, 'utf8'));

  console.log(`Deduplicating ${stores.length} stores...\n`);

  // Keep track of seen domains (normalize to handle variations)
  const seenDomains = new Map();
  const dedupedStores = [];

  for (const store of stores) {
    const normalizedDomain = store.domain.toLowerCase().replace(/^www\./, '');

    if (!seenDomains.has(normalizedDomain)) {
      seenDomains.set(normalizedDomain, true);
      dedupedStores.push(store);
    } else {
      console.log(`  Removing duplicate: ${store.domain} (${store.name})`);
    }
  }

  // Save deduplicated data
  fs.writeFileSync(rawDataPath, JSON.stringify(dedupedStores, null, 2));

  console.log(`\n✓ Removed ${stores.length - dedupedStores.length} duplicates`);
  console.log(`✓ Final count: ${dedupedStores.length} unique stores`);
  console.log(`✓ Saved to: ${rawDataPath}`);
}

if (require.main === module) {
  main();
}
